solution_code:
#include <iostream>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    if (a % b == 0)
        std::cout << "divisible: yes\n";
    else
        std::cout << "divisible: no\n";

    std::cout << "remainder: " << a % b << '\n';

    return 0;
}

