solution_code:
#include <iostream>

int main()
{
    int n = 0;
    std::cin >> n;

    int ones = n % 10;       // last digit: remainder when dividing by 10
    int tens = (n / 10) % 10; // second-to-last digit

    std::cout << "ones: " << ones << '\n';
    std::cout << "tens: " << tens << '\n';

    return 0;
}
